// Some portions generated by Codex

package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.util.concurrent.TimeUnit;

import org.eclipse.rdf4j.model.BNode;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.evaluation.sketch.SketchBasedJoinEstimator;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.eclipse.rdf4j.sail.lmdb.model.LmdbValue;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbSailStoreEstimatorLongIdTest {

	@Test
	void estimatorAnswersWithValueStoreIdsForIrisBlankNodesAndLiterals(@TempDir File dataDir) throws Exception {
		var vf = SimpleValueFactory.getInstance();
		IRI subject = vf.createIRI("urn:lmdb-long-id:s");
		BNode blankNode = vf.createBNode("lmdb-long-id-bnode");
		IRI predicate = vf.createIRI("urn:lmdb-long-id:p");
		IRI iriObject = vf.createIRI("urn:lmdb-long-id:o");
		Literal storedLiteral = vf.createLiteral("literal long enough to be stored outside inline encoding");
		Literal inlinedLiteral = vf.createLiteral(7);

		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc"));
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				connection.add(subject, predicate, iriObject);
				connection.add(blankNode, predicate, storedLiteral);
				connection.add(subject, predicate, inlinedLiteral);
				connection.commit();
			}

			LmdbSailStore backingStore = store.getBackingStore();
			SketchBasedJoinEstimator estimator = backingStore.getSketchBasedJoinEstimator();
			estimator.rebuild();
			assertTrue(estimator.awaitReady(10, TimeUnit.SECONDS));

			ValueStore valueStore = (ValueStore) backingStore.getValueFactory();
			long subjectId = valueStore.getId(subject);
			long blankNodeId = valueStore.getId(blankNode);
			long predicateId = valueStore.getId(predicate);
			long iriObjectId = valueStore.getId(iriObject);
			long storedLiteralId = valueStore.getId(storedLiteral);
			long inlinedLiteralId = valueStore.getId(inlinedLiteral);

			assertKnown(subjectId);
			assertKnown(blankNodeId);
			assertKnown(predicateId);
			assertKnown(iriObjectId);
			assertKnown(storedLiteralId);
			assertKnown(inlinedLiteralId);

			assertEquals(3.0d, estimator.cardinalitySingle(SketchBasedJoinEstimator.Component.P, predicateId), 0.0d);
			assertEquals(1.0d, estimator.cardinalitySingle(SketchBasedJoinEstimator.Component.S, blankNodeId), 0.0d);
			assertEquals(1.0d, estimator.cardinalitySingle(SketchBasedJoinEstimator.Component.O, storedLiteralId),
					0.0d);
			assertEquals(1.0d, estimator.cardinalitySingle(SketchBasedJoinEstimator.Component.O, inlinedLiteralId),
					0.0d);
			assertEquals(1.0d,
					estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PO, predicateId, iriObjectId), 0.0d);

			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				connection.remove(blankNode, predicate, storedLiteral);
				connection.commit();
			}

			assertEquals(0.0d, estimator.cardinalitySingle(SketchBasedJoinEstimator.Component.O, storedLiteralId),
					0.0d);
			assertEquals(2.0d, estimator.cardinalitySingle(SketchBasedJoinEstimator.Component.P, predicateId), 0.0d);
		} finally {
			repository.shutDown();
		}
	}

	private static void assertKnown(long id) {
		assertNotEquals(LmdbValue.UNKNOWN_ID, id);
	}
}
